        // Reset the active workspace to an empty document — clears all
        // entities (incl. relationship types), cells, and regions. Wholesale load
        // (history re-bases per D21, so it is not undoable — callers confirm).
        // View-state (viewport tabs/camera/lens config) is NOT touched. One home
        // for "reset workspace" (the Workspaces + Test-cases panels both call it).
        reset: function () { return store().loadDocument({ entities: {}, cells: {}, regions: [] }, { caret: { x: 0, y: 0 }, reason: "reset" }); },

        // history
        record: function (label, caretBefore, caretAfter) { var h = history(); if (h) h.record(label, caretBefore, caretAfter); },
        checkpoint: function (label, caretBefore, caretAfter) { var h = history(); if (h) h.checkpoint(label, caretBefore, caretAfter); },
        // transactions (§8.5): group several mutations from one user action into a
        // single undo entry. transact() is the safe wrapper (auto-balances); begin/
        // end are the explicit pair. No-ops if history is absent.
