      // While the popup input holds focus its keys are stopPropagation()'d, so this
      // only fires from genuine plane caret moves — never from typing in the picker.
      kernel.on("input:commit", function () { if (el) close(); });

      kernel.provide("grid-suggest", { open: open, close: close, registerProvider: registerProvider });
      // console handle — a lazy GETTER (resolved at the moment of use, §10.3), never an init-time stash
