        var sec = document.createElement("div"); sec.className = "gt-section";
        var head = document.createElement("div"); head.className = "gt-sechead";
        var car = document.createElement("span"); car.className = "gt-caret"; car.textContent = state ? "▸" : "▾";
        var lab = document.createElement("span"); lab.textContent = opts.title || "";
