            if (!rec || typeof rec !== "object" || !Array.isArray(rec.intents)) { cleanup(); window.alert("Import failed: that file isn't a GridText replay."); return; }
            var rp = replay(); var nm = f.name.replace(/\.replay\.json$/i, "").replace(/\.json$/i, "") || "Imported";
            if (rp && rp.importRecord) rp.importRecord(nm, rec);
