          vb.style.color = verdicts[m.id] === "pass" ? "var(--lt-green,#98c379)" : verdicts[m.id] === "fail" ? "var(--lt-red,#e06c75)" : "var(--lt-grey,#5c6370)";
          vb.title = "Last verify verdict this session — details in the console report";
