        var del = span("gt-rp-act del", "✕"); del.title = "Delete replay";
        del.addEventListener("click", function (e) { e.stopPropagation(); if (window.confirm('Delete replay "' + m.name + '"?')) { var rp = replay(); if (rp) rp.remove(m.id); } }); row.appendChild(del);
