        var rp = replay();

        // capture row
        var cap = div("gt-rp-cap");
        var rec = recorder(); var hasLast = !!(rec && rec.lastReplay && rec.lastReplay());
        var saveBtn = btn("gt-rp-btn", "＋ Save last recording"); saveBtn.disabled = !hasLast;
        saveBtn.title = hasLast ? "Save the last recording as a replay" : "Record something first (the status-bar ● control or GT.record.start())";
        saveBtn.addEventListener("click", function () { if (rp && rp.saveLast) rp.saveLast(); });
        cap.appendChild(saveBtn);
        cap.appendChild(div("gt-rp-hint", "Re-drives your recorded keystrokes & clicks at your current cursor. Your document isn't replaced, and zoom/pan are never played back — only the inputs."));
        body.appendChild(cap);

