        var relLabel = checkLabel("Relative to cursor", relative, function (v) { relative = v; });
        relLabel.title = "Play anchored at your current caret (clicks shift to match). Off = play at the recorded position.";
        ctl.appendChild(relLabel);
        body.appendChild(ctl);

