        progEl = div("gt-rp-prog"); progEl.style.display = "none";
        progEl.appendChild(span("gt-rp-progtxt", ""));
        stopBtn = btn("gt-rp-btn", "■ Stop"); stopBtn.addEventListener("click", function () { var r = replay(); if (r && r.cancel) r.cancel(); });
